// Validate required fields and normalise payload
const body = $input.first().json.body || $input.first().json;

const clientUrl = body.client_url;
const clientName = body.client_name;

if (!clientUrl || typeof clientUrl !== 'string') {
  throw new Error('Missing required field: client_url');
}
if (!clientName || typeof clientName !== 'string') {
  throw new Error('Missing required field: client_name');
}

// Normalise URL — ensure no trailing slash
const normUrl = clientUrl.replace(/\/+$/, '');

return [{
  json: {
    client_url: normUrl,
    client_name: clientName,
    competitors: Array.isArray(body.competitors) ? body.competitors : [],
    seed_keywords: Array.isArray(body.seed_keywords) ? body.seed_keywords : [],
    pipeline_run_id: null,
    started_at: new Date().toISOString()
  }
}];

// Merge pipeline_run_id into working context
const run = $input.first().json;
const prev = $('Validate_Payload').first().json;

return [{
  json: {
    ...prev,
    pipeline_run_id: run[0]?.id || run.id
  }
}];

// Parse sitemap XML, extract top 20 URLs prioritising shallow depth + service pages
const ctx = $('Merge_Run_ID').first().json;
const rawXml = $input.first().json.data || $input.first().json.body || '';

// Extract all <loc> values
const locMatches = rawXml.match(/<loc>([^<]+)<\/loc>/gi) || [];
const urls = locMatches
  .map(m => m.replace(/<\/?loc>/gi, '').trim())
  .filter(u => u.startsWith('http'));

// Score by depth (fewer slashes = shallower = higher priority)
// Boost /services/, /about, root
const scored = urls.map(u => {
  const path = u.replace(/^https?:\/\/[^/]+/, '') || '/';
  const depth = (path.match(/\//g) || []).length;
  const boost = /\/(services|about|process|case-stud)/i.test(path) ? -2 : 0;
  return { url: u, path, score: depth + boost };
});

scored.sort((a, b) => a.score - b.score);
const top20 = scored.slice(0, 20).map(s => ({ url: s.url, path: s.path }));

return top20.map(page => ({
  json: {
    ...ctx,
    page_url: page.url,
    page_path: page.path,
    all_pages: top20
  }
}));

// Extract title, H1, meta description, and truncated visible text from HTML
const ctx = $('SplitInBatches_Pages').item.json;
const html = $input.first().json.data || $input.first().json.body || '';

const title = (html.match(/<title[^>]*>([^<]+)<\/title>/i) || [])[1]?.trim() || '';
const h1 = (html.match(/<h1[^>]*>([^<]{0,200})<\/h1>/i) || [])[1]
  ?.replace(/<[^>]+>/g, '').trim() || '';
const metaDesc = (html.match(/<meta[^>]+name=['"]description['"][^>]+content=['"]([^'"]{0,300})['"][^>]*>/i)
  || html.match(/<meta[^>]+content=['"]([^'"]{0,300})['"][^>]+name=['"]description['"]/i)
  || [])[1]?.trim() || '';

// Strip tags and collapse whitespace for a truncated visible-text snippet
const visibleText = html
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 300);

return [{
  json: {
    url: ctx.page_url,
    path: ctx.page_path,
    title,
    h1,
    meta_description: metaDesc,
    visible_text: visibleText,
    // Carry forward context
    client_url: ctx.client_url,
    client_name: ctx.client_name,
    competitors: ctx.competitors,
    seed_keywords: ctx.seed_keywords,
    pipeline_run_id: ctx.pipeline_run_id,
    all_pages: ctx.all_pages
  }
}];

// Build LLM request body — inject crawled pages into prompt template
const pages = $input.first().json.data;
const firstPage = pages[0];

// Prompt is read from the prompt file content embedded here at build time
const systemPrompt = `You are an expert digital marketing strategist analysing a B2B service company's website to extract its service structure, ICP, and brand positioning. Return ONLY a raw JSON object matching the schema — no markdown, no code fences.`;

const userPrompt = `Analyse the following pages crawled from ${firstPage.client_url} and return a JSON object with: proposed_pillars, icp_signals, icp_persona_draft, brand_voice_hints, industries_addressed, competitor_mentions, confidence, notes.\n\nPages:\n${JSON.stringify(pages.map(p => ({ url: p.url, title: p.title, h1: p.h1, meta_description: p.meta_description, visible_text: p.visible_text })), null, 2)}`;

return [{
  json: {
    client_url: firstPage.client_url,
    client_name: firstPage.client_name,
    competitors: firstPage.competitors,
    seed_keywords: firstPage.seed_keywords,
    pipeline_run_id: firstPage.pipeline_run_id,
    llm_request: {
      model: 'google/gemini-2.0-flash-001',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      response_format: { type: 'json_object' },
      temperature: 0.2,
      max_tokens: 2048
    }
  }
}];

// Parse LLM response and build Slack questionnaire card with pre-filled values
const ctx = $('Build_LLM_Request').first().json;
const llmRaw = $input.first().json;

let analysis = {};
try {
  const content = llmRaw.choices?.[0]?.message?.content || '{}';
  analysis = JSON.parse(content);
} catch(e) {
  analysis = { proposed_pillars: [], icp_persona_draft: '', brand_voice_hints: '', industries_addressed: [], competitor_mentions: [], confidence: 'low', notes: 'LLM parse error: ' + e.message };
}

// Build Slack Block Kit message
const pillarsText = (analysis.proposed_pillars || []).map(p => `• ${p.name}: ${p.url_path || 'URL TBD'} — ${p.description}`).join('\n') || 'None detected — please fill in manually';
const nicheText = (analysis.industries_addressed || []).join(', ') || 'None detected';
const competitorText = [...(ctx.competitors || []), ...(analysis.competitor_mentions || [])].join(', ') || 'None';

// Log LLM cost
const inputTokens = llmRaw.usage?.prompt_tokens || 0;
const outputTokens = llmRaw.usage?.completion_tokens || 0;
const estimatedCostUsd = (inputTokens * 0.000001) + (outputTokens * 0.000002);

return [{
  json: {
    ...ctx,
    crawl_analysis: analysis,
    llm_cost: { input_tokens: inputTokens, output_tokens: outputTokens, usd: estimatedCostUsd },
    slack_message: {
      channel: 'C0B43A7QG5P',
      text: `🚀 New client onboarding: *${ctx.client_name}*`,
      blocks: [
        {
          type: 'header',
          text: { type: 'plain_text', text: `New Client Onboarding: ${ctx.client_name}`, emoji: true }
        },
        {
          type: 'section',
          text: { type: 'mrkdwn', text: `*Website:* ${ctx.client_url}\n*AI Confidence:* ${analysis.confidence || 'unknown'}\n*Notes:* ${analysis.notes || 'none'}` }
        },
        { type: 'divider' },
        {
          type: 'section',
          text: { type: 'mrkdwn', text: `*Proposed Service Pillars (from crawl):*\n${pillarsText}\n\n⬆️ Please verify these are correct. Edit the text fields below and submit.` }
        },
        {
          type: 'input',
          block_id: 'pillars_input',
          label: { type: 'plain_text', text: 'Service Pillars (one per line: name|url_path|description)' },
          element: {
            type: 'plain_text_input',
            action_id: 'pillars_value',
            multiline: true,
            initial_value: (analysis.proposed_pillars || []).map(p => `${p.name}|${p.url_path || ''}|${p.description}`).join('\n')
          }
        },
        {
          type: 'input',
          block_id: 'icp_input',
          label: { type: 'plain_text', text: 'ICP Persona (2-3 sentences)' },
          element: {
            type: 'plain_text_input',
            action_id: 'icp_value',
            multiline: true,
            initial_value: analysis.icp_persona_draft || ''
          }
        },
        {
          type: 'input',
          block_id: 'brand_voice_input',
          label: { type: 'plain_text', text: 'Brand Voice' },
          element: {
            type: 'plain_text_input',
            action_id: 'brand_voice_value',
            multiline: true,
            initial_value: analysis.brand_voice_hints || ''
          }
        },
        {
          type: 'input',
          block_id: 'niches_input',
          label: { type: 'plain_text', text: 'Target Niches (comma-separated)' },
          element: {
            type: 'plain_text_input',
            action_id: 'niches_value',
            initial_value: nicheText
          }
        },
        {
          type: 'input',
          block_id: 'competitors_input',
          label: { type: 'plain_text', text: 'Competitor Domains (comma-separated)' },
          element: {
            type: 'plain_text_input',
            action_id: 'competitors_value',
            initial_value: competitorText
          }
        },
        {
          type: 'input',
          block_id: 'review_tier_input',
          label: { type: 'plain_text', text: 'Review Tier' },
          element: {
            type: 'static_select',
            action_id: 'review_tier_value',
            initial_option: { text: { type: 'plain_text', text: 'tier_b_hitl_borderline' }, value: 'tier_b_hitl_borderline' },
            options: [
              { text: { type: 'plain_text', text: 'tier_a_ai_only' }, value: 'tier_a_ai_only' },
              { text: { type: 'plain_text', text: 'tier_b_hitl_borderline' }, value: 'tier_b_hitl_borderline' },
              { text: { type: 'plain_text', text: 'tier_c_hitl_random_sample' }, value: 'tier_c_hitl_random_sample' },
              { text: { type: 'plain_text', text: 'tier_d_hitl_full' }, value: 'tier_d_hitl_full' }
            ]
          }
        },
        {
          type: 'input',
          block_id: 'nav_strategy_input',
          label: { type: 'plain_text', text: 'Navigational Competitor Strategy' },
          element: {
            type: 'static_select',
            action_id: 'nav_strategy_value',
            initial_option: { text: { type: 'plain_text', text: 'allow_comparison_only' }, value: 'allow_comparison_only' },
            options: [
              { text: { type: 'plain_text', text: 'allow_comparison_only' }, value: 'allow_comparison_only' },
              { text: { type: 'plain_text', text: 'reject_all' }, value: 'reject_all' },
              { text: { type: 'plain_text', text: 'allow_all' }, value: 'allow_all' }
            ]
          }
        },
        {
          type: 'input',
          block_id: 'monthly_budget_input',
          label: { type: 'plain_text', text: 'Monthly API Budget USD' },
          element: {
            type: 'plain_text_input',
            action_id: 'monthly_budget_value',
            initial_value: '50'
          }
        },
        {
          type: 'actions',
          elements: [
            {
              type: 'button',
              text: { type: 'plain_text', text: 'Submit Questionnaire' },
              style: 'primary',
              action_id: 'submit_questionnaire',
              value: JSON.stringify({ pipeline_run_id: ctx.pipeline_run_id, client_name: ctx.client_name, client_url: ctx.client_url })
            }
          ]
        }
      ]
    }
  }
}];

// Parse Slack form submission payload
const body = $input.first().json.body || $input.first().json;
const payload = typeof body.payload === 'string' ? JSON.parse(body.payload) : body.payload || body;

const values = payload?.view?.state?.values || payload?.actions?.[0] || {};

// Helper to extract value from Slack block kit state
const get = (blockId, actionId) => {
  const block = values[blockId];
  if (!block) return null;
  const action = block[actionId];
  if (!action) return null;
  return action.value || action.selected_option?.value || null;
};

const pillarsRaw = get('pillars_input', 'pillars_value') || '';
const pillars = pillarsRaw.split('\n').filter(Boolean).map(line => {
  const [name, url_path, ...descParts] = line.split('|');
  return { name: name?.trim(), url_path: url_path?.trim() || null, description: descParts.join('|').trim() };
}).filter(p => p.name);

const nichesRaw = get('niches_input', 'niches_value') || '';
const niches = nichesRaw.split(',').map(n => n.trim()).filter(Boolean);

const competitorsRaw = get('competitors_input', 'competitors_value') || '';
const competitors = competitorsRaw.split(',').map(c => c.trim()).filter(Boolean);

// Retrieve context from action value
let ctxMeta = {};
try {
  ctxMeta = JSON.parse(payload?.actions?.[0]?.value || '{}');
} catch(e) {}

return [{
  json: {
    pipeline_run_id: ctxMeta.pipeline_run_id,
    client_name: ctxMeta.client_name,
    client_url: ctxMeta.client_url,
    questionnaire: {
      service_pillars: pillars,
      icp_persona: get('icp_input', 'icp_value') || '',
      brand_voice: get('brand_voice_input', 'brand_voice_value') || '',
      niches,
      competitors,
      review_tier: get('review_tier_input', 'review_tier_value') || 'tier_b_hitl_borderline',
      navigational_competitor_strategy: get('nav_strategy_input', 'nav_strategy_value') || 'allow_comparison_only',
      monthly_api_budget_usd: parseInt(get('monthly_budget_input', 'monthly_budget_value') || '50', 10)
    }
  }
}];

// Build cross-validation LLM request
const q = $json.questionnaire;
const crawlAnalysis = $('Build_Slack_Questionnaire').first().json.crawl_analysis;

const systemPrompt = 'You are a quality-control agent reviewing an onboarding questionnaire against website crawl data. Find meaningful inconsistencies. Return ONLY a raw JSON object — no markdown, no code fences.';

const userPrompt = `Compare the questionnaire answers against the site crawl analysis.\n\nCrawl analysis:\n${JSON.stringify(crawlAnalysis, null, 2)}\n\nQuestionnaire:\n${JSON.stringify(q, null, 2)}\n\nReturn: { has_flags, flags: [{ field, severity, issue, crawl_evidence, questionnaire_value, suggested_resolution }], summary }`;

return [{
  json: {
    ...$json,
    crawl_analysis: crawlAnalysis,
    llm_request: {
      model: 'google/gemini-2.0-flash-001',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      response_format: { type: 'json_object' },
      temperature: 0.1,
      max_tokens: 1024
    }
  }
}];

// Parse cross-validation response and decide routing
const ctx = $('Build_CrossVal_Request').first().json;
const llmRaw = $input.first().json;

let validation = {};
try {
  const content = llmRaw.choices?.[0]?.message?.content || '{}';
  validation = JSON.parse(content);
} catch(e) {
  validation = { has_flags: false, flags: [], summary: 'Parse error: ' + e.message };
}

const inputTokens = llmRaw.usage?.prompt_tokens || 0;
const outputTokens = llmRaw.usage?.completion_tokens || 0;
const costUsd = (inputTokens * 0.000001) + (outputTokens * 0.000002);

return [{
  json: {
    ...ctx,
    validation_pass1: validation,
    has_flags: validation.has_flags === true,
    llm_cost_crossval: { input_tokens: inputTokens, output_tokens: outputTokens, usd: costUsd }
  }
}];

