// Write client config, niches, competitor_brand_names, and gold_examples to Supabase
// This node runs after flags are resolved (or skipped if no flags)
const ctx = $input.first().json;
const q = ctx.questionnaire;
const analysis = ctx.crawl_analysis || {};

// Build client config JSONB
const config = {
  service_pillars: q.service_pillars,
  icp_persona: q.icp_persona,
  brand_voice: q.brand_voice,
  monthly_api_budget_usd: q.monthly_api_budget_usd || 50,
  expected_runs_per_month: 4,
  per_run_cost_ceiling_pct: 150,
  review_tier: q.review_tier,
  navigational_competitor_strategy: q.navigational_competitor_strategy,
  hitl_channels: ['slack'],
  hitl_routing: { borderline: 'slack', high_severity: ['slack'], taxonomy_suggestions: 'slack', cost_ceiling: ['slack'], quality_drift: ['slack'], onboarding_review: 'slack' },
  negative_overrides: [],
  positive_overrides: []
};

return [{
  json: {
    ...ctx,
    db_writes: {
      client: {
        name: q.client_name || ctx.client_name,
        slug: (q.client_name || ctx.client_name || '').toLowerCase().replace(/[^a-z0-9]+/g, '-'),
        canonical_domain: (ctx.client_url || '').replace(/^https?:\/\//, '').replace(/\/.*/, ''),
        config: config,
        onboarding_status: 'active'
      },
      niches: q.niches.map(n => ({ name: n, source: 'onboarding_declared' })),
      competitors: q.competitors.map(c => ({ domain: c })),
      gold_examples: (analysis.proposed_pillars || []).flatMap(p => [
        { keyword: p.name + ' agency', label: 'positive', notes: 'LLM-proposed seed from crawl' },
        { keyword: p.name + ' services', label: 'positive', notes: 'LLM-proposed seed from crawl' }
      ]).slice(0, 10)
    }
  }
}];

// Extract client ID from insert response and write niches
const client = $input.first().json;
const clientId = Array.isArray(client) ? client[0]?.id : client?.id;
const ctx = $('Build_DB_Writes').first().json;

return [{
  json: {
    ...ctx,
    client_id: clientId
  }
}];
